const template = $json.template || {};

const headerParams = template.header_params || {};
const rawBodyParams = template.body_params || {};
const buttonParams = template.buttons_params || {};

// Converte o array em objeto, removendo o índice 0.
// Mantém os índices 1, 2, 3... para corresponder a {1}, {2}, {3}.
const bodyParams = Array.isArray(rawBodyParams)
  ? Object.fromEntries(
      rawBodyParams
        .map((value, index) => [String(index), value])
        .filter(([index, value]) => index !== '0' && value != null)
    )
  : Object.fromEntries(
      Object.entries(rawBodyParams)
        .filter(([key, value]) =>
          key !== '0' &&
          key !== 'bodyParam0' &&
          value != null
        )
    );

let contentRenderizado = String(template.content || '');

// Substitui tanto {1} quanto {{1}}.
for (const [key, value] of Object.entries(bodyParams)) {
  const chaveEscapada = key.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

  contentRenderizado = contentRenderizado
    .replace(
      new RegExp(`{{\\s*${chaveEscapada}\\s*}}`, 'g'),
      String(value)
    )
    .replace(
      new RegExp(`{\\s*${chaveEscapada}\\s*}`, 'g'),
      String(value)
    );
}

return [
  {
    json: {
      ...$json,

      template: {
        ...template,
        body_params: bodyParams,
        content_renderizado: contentRenderizado
      },

      body_chatwoot: {
        content: contentRenderizado,
        message_type: 'outgoing',
        private: false,
        content_type: 'text',

        template_params: {
          name: template.nome,
          category: template.category || 'UTILITY',
          language: template.language || 'pt_BR',

          processed_params: {
            header: headerParams,
            body: bodyParams,
            buttons: Object.keys(buttonParams).length
              ? [
                  {
                    type: 'url',
                    parameter: buttonParams.url
                  }
                ]
              : []
          }
        }
      }
    }
  }
];

